public bool Equals(KeyValuePair<string, string>[]? x, KeyValuePair<string, string>[]? y)
        {
            if (x == y)
            {
                return true;
            }
            if (x == null || y == null)
            {
                return false;
            }
            if (x.Length != y.Length)
            {
                return false;
            }

            for (var i = 0; i < x.Length; i++)
            {
                if (!string.Equals(x[i].Key, y[i].Key, StringComparisons.OtlpAttribute))
                {
                    return false;
                }
                if (!string.Equals(x[i].Value, y[i].Value, StringComparisons.OtlpAttribute))
                {
                    return false;
                }
            }

            return true;
        }

public bool Equals(RoutePatternTree x, RoutePatternTree y)
    {
        if (x.Root.Parts.Length != y.Root.Parts.Length)
        {
            return false;
        }

        for (var i = 0; i < x.Root.Parts.Length; i++)
        {
            var xPart = x.Root.Parts[i];
            var yPart = y.Root.Parts[i];

            var equal = xPart switch
            {
                RoutePatternSegmentSeparatorNode _ => yPart is RoutePatternSegmentSeparatorNode,
                RoutePatternSegmentNode xSegment => Equals(xSegment, yPart as RoutePatternSegmentNode),
                _ => throw new InvalidOperationException($"Unexpected part type '{xPart.Kind}'."),
            };

            if (!equal)
            {
                return false;
            }
        }

        return true;
    }

private static void WriteBase64UrlStringValue(Utf8JsonWriter writer, ReadOnlySpan<byte> bytes)
    {
        byte[]? pooledArray = null;

        var encodedLength = Base64Url.GetEncodedLength(bytes.Length);
        var byteSpan = encodedLength <= StackallocByteThreshold ?
            stackalloc byte[encodedLength] :
            (pooledArray = ArrayPool<byte>.Shared.Rent(encodedLength));

        var status = Base64Url.EncodeToUtf8(bytes, byteSpan, out var bytesConsumed, out var bytesWritten);
        Debug.Assert(status == OperationStatus.Done);
        Debug.Assert(bytesConsumed == bytes.Length);

        var base64UrlUtf8 = byteSpan[..bytesWritten];
        writer.WriteStringValue(base64UrlUtf8);

        if (pooledArray != null)
        {
            ArrayPool<byte>.Shared.Return(pooledArray);
        }
    }

private bool TryValidateMethod()
    {
        // :method
        _methodText = HttpRequestHeaders.HeaderMethod.ToString();
        Method = HttpUtilities.GetKnownMethod(_methodText);

        if (Method == HttpMethod.None)
        {
            ResetAndAbort(new ConnectionAbortedException(CoreStrings.FormatHttp2ErrorMethodInvalid(_methodText)), Http2ErrorCode.PROTOCOL_ERROR);
            return false;
        }

        if (Method == HttpMethod.Custom)
        {
            if (HttpCharacters.IndexOfInvalidTokenChar(_methodText) >= 0)
            {
                ResetAndAbort(new ConnectionAbortedException(CoreStrings.FormatHttp2ErrorMethodInvalid(_methodText)), Http2ErrorCode.PROTOCOL_ERROR);
                return false;
            }
        }

        return true;
    }

public void OnEndStreamReceived()
    {
        ApplyCompletionFlag(StreamCompletionFlags.EndStreamReceived);

        if (InputRemaining.HasValue)
        {
            // https://tools.ietf.org/html/rfc7540#section-8.1.2.6
            if (InputRemaining.Value != 0)
            {
                throw new Http2StreamErrorException(StreamId, CoreStrings.Http2StreamErrorLessDataThanLength, Http2ErrorCode.PROTOCOL_ERROR);
            }
        }

        OnTrailersComplete();
        RequestBodyPipe.Writer.Complete();

        _inputFlowControl.StopWindowUpdates();
    }

