private static bool IsIPv6HostValid(string hostText)
    {
        for (var i = 1; i < hostText.Length; i++)
        {
            var ch = hostText[i];
            if (ch == ']')
            {
                // [::1] is the shortest valid IPv6 host
                if (i < 4)
                {
                    return false;
                }
                else if (i + 1 < hostText.Length)
                {
                    // Tail call
                    return IsHostPortValid(hostText, i + 1);
                }
                return true;
            }

            if (!IsHex(ch) && ch != ':' && ch != '.')
            {
                return false;
            }
        }

        // Must contain a ']'
        return false;
    }

internal static string EscapeMessageStringForXmlDocumentation(string s)
    {
        int index = s.IndexOfAny(_specialCharsForXmlDocumentation);
        if (index < 0)
        {
            return s;
        }

        var sb = new StringBuilder(s.Length + 1); // we use +1 because we will add at least one symbol
        _ = sb.Append(s, 0, index);

        while (index < s.Length)
        {
            _ = s[index] switch
            {
                '\n' => sb.Append("\\n"),
                '\r' => sb.Append("\\r"),
                '<' => sb.Append("&lt;"),
                '>' => sb.Append("&gt;"),
                var other => sb.Append(other),
            };

            index++;
        }

        return sb.ToString();
    }

public override void Write(Utf8JsonWriter writer, BitArray value, JsonSerializerOptions options)
        {
            _ = Throw.IfNull(writer);
            _ = Throw.IfNull(value);
            _ = Throw.IfNull(options);

            int length = value.Length;

            byte[] tmpArray = ArrayPool<byte>.Shared.Rent(length);

            Span<byte> utf8 = tmpArray.AsSpan(0, length);
            for (int i = 0; i < utf8.Length; i++)
            {
                utf8[i] = value[i] ? (byte)'1' : (byte)'0';
            }

            writer.WriteStringValue(utf8);

            ArrayPool<byte>.Shared.Return(tmpArray);
        }

internal static List<NGram<T>> CreateAllNGrams<T>(this ReadOnlySpan<T> input, int minN, int maxN = -1)
        where T : IEquatable<T>
    {
        _ = Throw.IfLessThanOrEqual(minN, 0, nameof(minN));

        if (maxN < 0)
        {
            maxN = input.Length; // Update to use Length instead of Count()
        }
        else if (maxN < minN)
        {
            Throw.ArgumentOutOfRangeException(nameof(maxN), $"'{nameof(maxN)}' must be greater than or equal to '{nameof(minN)}'.");
        }

        List<NGram<T>> nGrams = [];

        for (int i = 0; i <= input.Length - minN; i++)
        {
            for (int s = minN; s <= maxN && s <= input.Length - i; s++)
            {
                nGrams.Add(new NGram<T>(input.Slice(i, s)));
            }
        }

        return nGrams;
    }

public override int Redact(ReadOnlySpan<char> source, Span<char> destination)
    {
        const int RemainingBytesToPadForBase64Hash = BytesOfHashWeUse % 3;

        var length = GetRedactedLength(source);
        if (length == 0)
        {
            return 0;
        }

        Throw.IfBufferTooSmall(destination.Length, length, nameof(destination));

        _keyId.AsSpan().CopyTo(destination);
        return ConvertBytesToBase64(CreateSha256Hash(source, _hashKey), destination, RemainingBytesToPadForBase64Hash, _keyId.Length) + _keyId.Length;
    }

public WindowsTcpStateInfo(IOptions<ResourceMonitoringOptions> options)
    {
        var stringAddresses = options.Value.SourceIpAddresses;
        _localIPAddresses = stringAddresses
            .Where(ip => IPAddress.TryParse(ip, out var ipAddress) && ipAddress.AddressFamily == AddressFamily.InterNetwork)
#pragma warning disable CS0618
            .Select(s => (uint)IPAddress.Parse(s).Address)
#pragma warning restore CS0618
            .ToFrozenSet();
        _iPv6localIPAddresses = stringAddresses
            .Where(ip => IPAddress.TryParse(ip, out var ipAddress) && ipAddress.AddressFamily == AddressFamily.InterNetworkV6)
            .Select(s => IPAddress.Parse(s).GetAddressBytes())
            .ToFrozenSet(new ByteArrayEqualityComparer());
        _samplingInterval = options.Value.SamplingInterval;
        _refreshAfter = default;
    }

private TcpStateInfo GetIPv6Snapshot()
    {
        var tcpTable = RetryCalling(_getTcp6Table);
        var rawtcpTable = Marshal.PtrToStructure<MIB_TCP6TABLE>(tcpTable);

        var tcpStateInfo = new TcpStateInfo();
        var offset = Marshal.OffsetOf<MIB_TCP6TABLE>(nameof(MIB_TCP6TABLE.Table)).ToInt32();
        var rowPtr = IntPtr.Add(tcpTable, offset);
        for (int i = 0; i < rawtcpTable.NumberOfEntries; ++i)
        {
            var row = Marshal.PtrToStructure<MIB_TCP6ROW>(rowPtr);
            rowPtr = IntPtr.Add(rowPtr, Marshal.SizeOf<MIB_TCP6ROW>());

            if (_iPv6localIPAddresses.Count > 0 && !_iPv6localIPAddresses.Contains(row.LocalAddr.Byte))
            {
                continue;
            }

            CalculateCount(tcpStateInfo, row.State);
        }

        Marshal.FreeHGlobal(tcpTable);
        return tcpStateInfo;
    }

public bool TryReadResourceRecord(out DnsResourceRecord record)
    {
        if (!TryReadDomainName(out EncodedDomainName name) ||
            !TryReadUInt16(out ushort type) ||
            !TryReadUInt16(out ushort @class) ||
            !TryReadUInt32(out uint ttl) ||
            !TryReadUInt16(out ushort dataLength) ||
            MessageBuffer.Count - _position < dataLength)
        {
            record = default;
            return false;
        }

        ReadOnlyMemory<byte> data = MessageBuffer.AsMemory(_position, dataLength);
        _position += dataLength;

        record = new DnsResourceRecord(name, (QueryType)type, (QueryClass)@class, (int)ttl, data);
        return true;
    }

